const data = JSON.parse($input.item.json.payload);
const temp = data.temperature;
const humidity = data.humidity;

let alerts = [];
let severity = 'normal';

if (temp < 15) {
  alerts.push('❄️ Sıcaklık çok düşük: ' + temp + '°C');
  severity = 'critical';
} else if (temp > 35) {
  alerts.push('🔥 Sıcaklık çok yüksek: ' + temp + '°C');
  severity = 'critical';
} else if (temp < 18 || temp > 30) {
  alerts.push('⚠️ Sıcaklık normal aralıkta değil: ' + temp + '°C');
  severity = 'warning';
}

if (humidity < 40) {
  alerts.push('💨 Nem çok düşük: %' + humidity);
  severity = Math.max(severity, 'warning');
} else if (humidity > 80) {
  alerts.push('💧 Nem çok yüksek: %' + humidity);
  severity = Math.max(severity, 'warning');
}

return {
  json: {
    sensor: 'temperature_humidity',
    temperature: temp,
    humidity: humidity,
    alerts: alerts,
    severity: severity,
    timestamp: new Date(),
    hasAlerts: alerts.length > 0
  }
};

const data = JSON.parse($input.item.json.payload);
const zones = data.zones;

let alerts = [];
let criticalZones = [];

zones.forEach(zone => {
  if (zone.moisture < 20) {
    criticalZones.push(zone.name);
    alerts.push('🚨 ' + zone.name + ' çok kuru: %' + zone.moisture);
  } else if (zone.moisture < 30) {
    alerts.push('⚠️ ' + zone.name + ' sulamaya ihtiyaç var: %' + zone.moisture);
  }
});

return {
  json: {
    sensor: 'soil',
    zones: zones,
    alerts: alerts,
    criticalZones: criticalZones,
    severity: criticalZones.length > 0 ? 'critical' : (alerts.length > 0 ? 'warning' : 'normal'),
    timestamp: new Date(),
    hasAlerts: alerts.length > 0
  }
};

const data = JSON.parse($input.item.json.payload);
const lightPercent = data.light_percent;
const level = data.level;

let alerts = [];
let severity = 'normal';

const hour = new Date().getHours();
const isDaytime = (hour >= 6 && hour <= 18);

if (isDaytime && lightPercent < 30) {
  alerts.push('☀️ Gündüz ışık yetersiz: %' + lightPercent);
  severity = 'warning';
}

return {
  json: {
    sensor: 'light',
    lightPercent: lightPercent,
    level: level,
    isDaytime: isDaytime,
    alerts: alerts,
    severity: severity,
    timestamp: new Date(),
    hasAlerts: alerts.length > 0
  }
};
